// overload
function area(a, b) {
  if (b === undefined) return a * a;
  return a * b;
}
console.log(area(5), area(3, 4));

from functools import singledispatch
@singledispatch
def process(val):
    raise NotImplementedError(f"Cannot overload for {type(val)}")
@process.register(int)
def _(val):
    return val * 2

class Calculator {
  public int overload(int a) { return a * a; }
  public int overload(int a, int b) { return a * b; }
}
